import{_ as i,o as r,c as l,ag as n}from"./chunks/framework.DXGyWiRo.js";const s="/images/uebung095.jpg",t="/images/uebung097.jpg",a="/images/uebung096.jpg",c=JSON.parse('{"title":"Übung Lektion 58","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung58.md","filePath":"lektionen/uebung58.md"}'),p={name:"lektionen/uebung58.md"};function o(d,e,g,m,h,u){return r(),l("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-58" tabindex="-1">Übung Lektion 58 <a class="header-anchor" href="#ubung-lektion-58" aria-label="Permalink to &quot;Übung Lektion 58&quot;">​</a></h1><p><em>Erstmals hier publiziert:</em> 2009-03-12</p><p>Falls Sie die diakritischen Zeichen nicht dargestellt bekommen, installieren Sie eine Schrift mit Diakritika wie z.B. Tahoma.</p><p>A) Bestimmen und übersetzen Sie ohne Hilfsmittel folgende Formen und bilden Sie die entsprechenden Formen des i-Aorist:</p><ol><li><p>औहे - ऊह्  1Ā 1.sg.Impf.Ā ich schob - औहिषि</p></li><li><p>जाग्रति - जागृ 2P 3.pl.Ind.Präs.P sie sind wach - अजागरिषुः</p></li><li><p>जीर्यन्ति - जॄ 4P 3.pl.Ind.Präs.P sie altern - अजारिषुः</p></li><li><p>आनर्च - अर्च् 1P verehren 1.3.sg.2.pl.Perf.P  - आर्चिषम् । आर्चीत् । आर्चिष्ट</p></li><li><p>खादामः - खाद् 1P 1.pl.Ind.Präs.P wir kauen - अखादिष्म</p></li><li><p>नेद - नद् 1P 2.pl.Perf.P ihr ertöntet - अनादिष्ट । अनदिष्ट</p></li><li><p>आश्नीत -अश् 9P 2.pl.Impf.P ihr aßt - आशिष्ट</p></li><li><p>पुनते - पू 9U 3.pl.Ind.Präs.Ā sie reinigen im eigenen Interesse - अपविषत</p></li><li><p>अशेरत - शी 2Ā 3.pl.Impf.Ā sie lagen - अशयिषत</p></li><li><p>इयेषिथ - इष् 6P 2.sg.Perf.P du hast gewünscht - ऐषीः</p></li><li><p>आर्च्छत्  - ऋ 1P 3.sg.Impf.P er ging - आरीत्</p></li><li><p>अर्हन्ति - अर्ह् 1P 3.pl.Ind.Präs.P sie sind würdig - आर्हिषुः</p></li><li><p>ऊदुः - वद् 1P 3.pl.Perf.P sie sprachen - अवादिषुः</p></li><li><p>इन्त्से - इन्ध् 7Ā 2.sg.Ind.Präs,Ā du zündest an - ऐन्धिष्ठाः</p></li><li><p>आध्वे - आस् 2Ā 2.pl.Ind.Präs.Ā ihr sitzt -आसिध्वम्</p></li><li><p>कल्पे - कॢप् 1.sg.Ind.Präs.Ā ich passe -अकल्पिषि</p></li><li><p>आनीत् - अन् 2P 3.sg.Impf.P er atmete - आनीत्</p></li><li><p>ऐक्षध्वम् - ईक्ष् 1Ā 2.pl.Impf.Ā ihr saht - ऐक्षिध्वम्</p></li><li><p>अचेतः - चित् 1P 2.sg.Impf.P du nahmst wahr - अचेतीः</p></li></ol><p><img src="'+s+'" alt=""><br> Abb.: तब्लाः,  अनदिष्ट ॥<br> [Bildquelle: Kaustav Bhattacharya. -- <a href="http://www.flickr.com/photos/astrolondon/224826916/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/astrolondon/224826916/</a>. -- Zugriff am 2009-03-12. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>B) Übersetzen und bestimmen Sie folgende Formen:</p><p><img src="'+t+'" alt=""><br> Abb.: मातुलङ्गविक्रेतायं ना ॥<br> Pune - पुणे<br> [Bildquelle: Anushruti RK. -- <a href="http://www.flickr.com/photos/anushruti/1724235028/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/anushruti/1724235028/</a>. -- Zugriff am 2009-03-12. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><ol><li>अनेढ्वम् - नी 1U 2.pl.Aor(4).Ā ihr führtet im eigenen Interesse</li><li>एनयोः - एतद् । इदम् Gen.Lok.du.m.f.n. dieser beiden / in diesen beiden</li><li>अष्टौ - अष्ट Nom.Vok.Akk. acht</li><li>चक्रम - क्रम् 2.pl.Perf.P ihr seid geschritten</li><li>ना - नृ m. Nom.sg. der Mann</li><li>अत्तः - अद् 2P 3.du.Ind.Präs.P ihr beide esst</li><li>अधृत - धृ 1U 3.sg.Aor(4).Ā er hielt im eigenen Interesse fest ; अ + PPP zu धृ 1U Vok.sg.m. Unfester!</li><li>ईहेरन् - ईह् 1Ā 3.pl.Opt.Ā sie mögen begehren</li><li>अधिजगे - अधि-इ 2Ā 1.3.sg.Perf.Ā ich / er studierte</li><li>जग्म - गम् 1P 2.pl.Perf.P ihr seid gegangen</li><li>अघ्रात् - घ्रा 1P 3.sg.Aor(1).P er roch</li><li>अद्राक्ष्म - दृश् 1.pl.Aor(4).P wir sahen</li><li>अस्थाः - अस् 4P 2.sg.Injunktiv.Aor(2).P werfe [+ मा nicht]</li><li>अधमः - ध्मा 1P 2.sg.Impf.P du hast geblasen ; अधम 3 Nom.sg.m. der unterste</li><li>आनर्ध - ऋध् 5P 1.3.sg.Perf.P ich / er gedieh</li><li>पथोः - पथ् m. Gen.Lok.du der beiden Wege / auf beiden Wegen</li><li>जेता - जेतृ m. Nom.sg. der Sieger</li><li>श्वा - श्वन् m. Nom.sg. der Hund</li><li>स्वः - अस् 2P 1.du.Ind.Präs.P wir beide sind ; स्व 3 Nom.sg.m. der eigene</li><li>यदृच्छया - Adv. zufällig, von selbst ...</li><li>अकार्षम् - कृ 8U 1.sg.Aor(4).P ich machte</li><li>क्रीणीथः - क्री 9U 2.du.Ind.Präs.P ihr beide kauft</li><li>क्रीणीथ - क्री 9U 2.pl.Ind.Präs.P ihr kauft</li><li>जानानि - ज्ञा 9U 1.sg.Imperativ.P ich will erkennen</li><li>भोः - Indekl. he!, he da!</li><li>अजैष्त - जि 1P 2.pl.Aor(4).p ihr siegtet</li><li>पुरा - Adv. früher, einst</li><li>देवा - देवृ m. Nom.sg. Gattenbruder, Schwager (der Frau)</li><li>गन्धी - गन्धिन् 3 Nom.sg.m der durch Geruch besonders gekennzeichnete</li><li>ईय - इ 2P 2.pl.Perf.P ihr seid gegangen</li><li>नाना - Adv. auf verschiedene Weise</li><li>देह - दह् 1P 2.pl.Perf.P ihr habt verbrannt ; देह m. Vok.sg. Leib!</li><li>अतत - तन् 8U 3.sg.Aor(4/1).Ā er spannte im eigenen Interesse auf ;अ + PPP zu तन् 8U Vok.sg.m. Unaufgespannter!</li><li>आप्स्यावः - आप् 5P 1.du.Fut.P wir beide werden erlangen</li><li>अतौत्त - तुद् 6U 2.pl.Aor(4).P ihr habt geschlagen</li><li>इमे - इदम् 3 Nom.pl.m.Nom.Akk.du.f.n. diese / diese beiden</li><li>इतः - इ 2P 3.du.Ind.Präs.P ihr beide geht ; इतस् Adv. von hier</li><li>दद - दा 3U 2.pl.Perf.P ihr gabt</li><li>अञ्ज्वः - अञ्ज् 7P 1.du.Ind.Präs.P wir beide salben</li></ol><p><img src="'+a+'" alt=""><br> Abb.: श्वा श्वानमघ्रात् ॥<br> Hampi - ಹಂಪೆ<br> [Bildquelle: Laertes. -- <a href="http://www.flickr.com/photos/jonhurd/2367038594/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/jonhurd/2367038594/</a>. -- Zugriff am 2009-03-12. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p>',11)])])}const f=i(p,[["render",o]]);export{c as __pageData,f as default};
